import{_ as a,o as t,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Email Overview","description":"","frontmatter":{"title":"Email Overview","slug":"email-overview"},"headers":[],"relativePath":"marketer-hub/email-overview.md","filePath":"marketer-hub/email-overview.md"}'),r={name:"marketer-hub/email-overview.md"};function n(s,e,l,c,m,h){return t(),i("div",null,[...e[0]||(e[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Deep Linked Email allows you to automatically convert your email links into multi-platform deep links that take users directly to content in the app on mobile devices, while still maintaining the same web experience for desktop and mobile users without the app.</p><p>Using Branch you can have deeper insights into engagement with consumers, not just clicks, but also application installs, opens, purchase etc. Driving your customers into the app will significantly increase user engagement as demonstrated in case studies from <a href="https://cdn.us.document360.io/082e8be0-ad38-4650-9062-689a75e517a2/Images/Documentation/CS-Airbnb.pdf" target="_blank" rel="noreferrer">Airbnb</a> and <a href="https://cdn.us.document360.io/082e8be0-ad38-4650-9062-689a75e517a2/Images/Documentation/CS-Instacart-DLE.pdf" target="_blank" rel="noreferrer">Instacart</a>, who are already using Branch Links in their emails.</p><h2 id="how-it-works" tabindex="-1">How it Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it Works&quot;">​</a></h2><p>Traditionally, getting links to work in email has always been fairly time-consuming and sometimes futile process. If you use an Email Service Provider (ESP) to send your marketing emails, deep linking into your app has always been out of the question as it simply doesn’t work - due to broken Domain-App association - thus users can only be routed to your mobile web content.</p><p>Branch solves this problem by integrating directly with your ESP and acting as a proxy between your ESP’s server and your customized domain name. As the proxy, Branch not only forwards all of the information associated with the link and click to your ESP, but also receives information back including personalized content which Branch uses when redirecting the user to your app or mobile web.</p><p><strong>Click Flow with Branch Email Integration</strong></p><p><strong>Click Flow with Branch Email for Integrations that Always Open the App</strong></p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Access to Branch Email is included in our Engagement product. Learn more on our <a href="./packaging.html">pricing</a> page.</p><h2 id="more-information" tabindex="-1">More information <a class="header-anchor" href="#more-information" aria-label="Permalink to &quot;More information&quot;">​</a></h2><p>For more detailed information on integrating Email with Branch, visit our <a href="./email.html">developer documentation</a>.</p>',12)])])}const p=a(r,[["render",n]]);export{u as __pageData,p as default};
